//! Compiler-emitted rules for the World Sim engine.
//!
//! Everything under `events/` and the body of `schema.rs` is generated by
//! `dsl_compiler` from `assets/sim/*.sim`. Regenerate with:
//!
//! ```bash
//! cargo run --bin xtask -- compile-dsl
//! ```
//!
//! This `lib.rs` is hand-written — it is the stable module root that pulls
//! the generated modules into one crate.

pub mod events;
pub mod id_serde;
pub mod schema;

pub use events::Event;
pub use schema::EVENT_HASH;
